INSERT INTO `observer_messages` (`id`, `observer_id`, `target_user_id`, `title`, `message`, `is_read`, `deleted_by`, `deleted_at`, `created_at`) VALUES
(1, 40, 19, 'یی', 'یی', 1, 40, '2026-06-06 09:21:10', '2026-06-06 09:05:51'),
(2, 40, 18, 'پیشرفت اهداف', 'با سلام و احترام،\r\n\r\nپیرو درخواست آقای فرشباف و همکاران محترم، مبنای تسعیر آیتم فروش اقساطی از «گرم» به «ریال» تغییر یافت.\r\n\r\nدر صورت بروز هرگونه مشکل، مراتب را اطلاع‌رسانی نمایید.', 0, 40, '2026-06-09 15:41:15', '2026-06-09 08:46:24'),
(3, 40, 19, 'پیشرفت اهداف', 'با سلام و احترام،\r\n\r\nپیرو درخواست آقای فرشباف و همکاران محترم، مبنای تسعیر آیتم فروش اقساطی از «گرم» به «ریال» تغییر یافت.\r\n\r\nدر صورت بروز هرگونه مشکل، مراتب را اطلاع‌رسانی نمایید.', 0, 40, '2026-06-09 15:41:20', '2026-06-09 08:46:24'),
(4, 40, 31, 'پیشرفت اهداف', 'با سلام و احترام،\r\n\r\nپیرو درخواست آقای فرشباف و همکاران محترم، مبنای تسعیر آیتم فروش اقساطی از «گرم» به «ریال» تغییر یافت.\r\n\r\nدر صورت بروز هرگونه مشکل، مراتب را اطلاع‌رسانی نمایید.', 0, 40, '2026-06-09 15:41:18', '2026-06-09 08:46:24'),
(5, 40, 18, 'ثبت اهداف', 'سلام و  وقتتون بخیر خدمت همگاران گرامی\r\nثبت روزانه پیشرفت اهداف حاصل جمع جبری هر آیتمی هست که ثبت میکنین\r\nاین عمل باعث میشود تا جمع جبری طی 4 ماه تایین شده دقیقا همان مانده ثبت شده در نرم افزار زرگر باشد\r\nموفق باشید.', 0, 40, '2026-06-11 09:10:12', '2026-06-09 15:58:32'),
(6, 40, 19, 'ثبت اهداف', 'سلام و  وقتتون بخیر خدمت همگاران گرامی\r\nثبت روزانه پیشرفت اهداف حاصل جمع جبری هر آیتمی هست که ثبت میکنین\r\nاین عمل باعث میشود تا جمع جبری طی 4 ماه تایین شده دقیقا همان مانده ثبت شده در نرم افزار زرگر باشد\r\nموفق باشید.', 0, 40, '2026-06-11 09:10:16', '2026-06-09 15:58:32'),
(7, 40, 31, 'ثبت اهداف', 'سلام و  وقتتون بخیر خدمت همگاران گرامی\r\nثبت روزانه پیشرفت اهداف حاصل جمع جبری هر آیتمی هست که ثبت میکنین\r\nاین عمل باعث میشود تا جمع جبری طی 4 ماه تایین شده دقیقا همان مانده ثبت شده در نرم افزار زرگر باشد\r\nموفق باشید.', 0, 40, '2026-06-11 09:10:19', '2026-06-09 15:58:32');
